+  private onHealthStatusChange(check: TeammateHealthCheck): void {
+    this.emit('health:changed', check);
+
+    if (check.status === 'unhealthy') {
+      this.metrics.increment('healthChecksFailed');
+      this.emit('health:unhealthy', check);
