+  async findBestTeammateForTask(
+    teamName: string,
+    task: {
+      id: string;
+      description: string;
+      requiredSkills: string[];
+      priority?: 'urgent' | 'high' | 'normal' | 'low';
+    }
+  ): Promise<RoutingDecision | null> {
+    if (!this.optimizersEnabled || !this.semanticRouter) {
+      return null;
+    }
+
+    const team = this.activeTeams.get(teamName);
+    if (!team) {
+      return null;
