+    const teamState: TeamState = {
+      name: fullConfig.name,
+      createdAt: new Date(),
+      teammates: [],
+      pendingJoinRequests: [],
+      activePlans: [],
+      messageCount: 0,
+      topology: fullConfig.topology,
+      context: {
+        teamName: fullConfig.name,
+        sharedVariables: {},
+        inheritedPermissions: [],
+        workingDirectory: process.cwd(),
