+  /**
+   * Pause plan execution
+   */
+  async pausePlan(teamName: string, planId: string): Promise<void> {
+    this.ensureAvailable();
+
+    const team = this.getTeamOrThrow(teamName);
+    const plan = this.getPlanOrThrow(team, planId);
