+      throw new TeammateError(
+        `Plan ${planId} is not executing`,
+        TeammateErrorCode.PLAN_NOT_APPROVED,
+        teamName
+      );
+    }
+
+    plan.status = 'paused';
+    plan.pausedAt = plan.currentStep;
